const browser = (function () {
    "use strict";

    const data = {
        name: null,
        version: null,
        os: null,
        osVersion: null,
        touch: null,
        mobile: null,
    };

    function detectBrowser() {
        const userAgent = navigator.userAgent;
        const browserData = [
            ["firefox", /Firefox\/([0-9\.]+)/],
            ["bb", /BlackBerry.+Version\/([0-9\.]+)/],
            ["bb", /BB[0-9]+.+Version\/([0-9\.]+)/],
            ["opera", /OPR\/([0-9\.]+)/],
            ["opera", /Opera\/([0-9\.]+)/],
            ["edge", /Edge\/([0-9\.]+)/],
            ["safari", /Version\/([0-9\.]+).+Safari/],
            ["chrome", /Chrome\/([0-9\.]+)/],
            ["ie", /MSIE ([0-9]+)/],
            ["ie", /Trident\/.+rv:([0-9]+)/],
        ];

        for (const [name, regex] of browserData) {
            if (userAgent.match(regex)) {
                data.name = name;
                data.version = parseFloat(RegExp.$1);
                break;
            }
        }
    }

    function detectOS() {
        const userAgent = navigator.userAgent;
        const osData = [
            ["ios", /([0-9_]+) like Mac OS X/, (version) => version.replace(/_/g, ".")],
            ["ios", /CPU like Mac OS X/, () => 0],
            ["wp", /Windows Phone ([0-9\.]+)/, (version) => version],
            ["android", /Android ([0-9\.]+)/, (version) => version],
            ["mac", /Macintosh.+Mac OS X ([0-9_]+)/, (version) => version.replace(/_/g, ".")],
            ["windows", /Windows NT ([0-9\.]+)/, (version) => version],
            ["bb", /BlackBerry.+Version\/([0-9\.]+)/, (version) => version],
            ["bb", /BB[0-9]+.+Version\/([0-9\.]+)/, (version) => version],
            ["linux", /Linux/, () => null],
            ["bsd", /BSD/, () => null],
            ["unix", /X11/, () => null],
        ];

        for (const [name, regex, versionExtractor] of osData) {
            if (userAgent.match(regex)) {
                data.os = name;
                data.osVersion = versionExtractor ? versionExtractor(RegExp.$1) : RegExp.$1;
                break;
            }
        }

        if (data.os === "mac" && "ontouchstart" in window) {
            // Check if the screen dimensions match one of the known dimensions for Macs with a touchbar
            const isIOSOnMac = [
                [1024, 1366],
                [834, 1112],
                [810, 1080],
                [768, 1024],
            ].some(([width, height]) => screen.width === width && screen.height === height);

            if (isIOSOnMac) {
                data.os = "ios";
            }
        }
    }

    data.touch = data.os === "wp" ? navigator.msMaxTouchPoints > 0 : "ontouchstart" in window;
    data.mobile = ["wp", "android", "ios", "bb"].includes(data.os);

    return {
        name: data.name,
        version: data.version,
        os: data.os,
        osVersion: data.osVersion,
        touch: data.touch,
        mobile: data.mobile,
    };
    detectBrowser();
    detectOS();

    return browser;
});